using System.Data;using CalculadoraUnimex.Api.Models;using Microsoft.AspNetCore.Mvc;using Microsoft.Data.SqlClient;
namespace CalculadoraUnimex.Api.Controllers;
[ApiController][Route("api/auth")]public sealed class AuthController(IConfiguration config):ControllerBase
{
 [HttpPost("login")]public async Task<ActionResult<ApiResult>> Login(LoginRequest r){if(string.IsNullOrWhiteSpace(r.Correo)||string.IsNullOrWhiteSpace(r.Password))return BadRequest(new ApiResult(false,"Correo y contraseña son obligatorios."));try{await using var c=new SqlConnection(config.GetConnectionString("DefaultConnection"));await c.OpenAsync();await using var cmd=new SqlCommand("sp_Usuario_Login",c){CommandType=CommandType.StoredProcedure};cmd.Parameters.Add("@Correo",SqlDbType.NVarChar,150).Value=r.Correo.Trim();cmd.Parameters.Add("@Password",SqlDbType.NVarChar,100).Value=r.Password;var existe=Convert.ToInt32(await cmd.ExecuteScalarAsync());return existe>0?Ok(new ApiResult(true,"Inicio de sesión correcto.")):Unauthorized(new ApiResult(false,"Correo o contraseña incorrectos."));}catch(Exception ex){return StatusCode(500,new ApiResult(false,"Error de base de datos: "+ex.Message));}}
 [HttpPost("register")]public async Task<ActionResult<ApiResult>> Register(RegisterRequest r){if(string.IsNullOrWhiteSpace(r.Nombre)||string.IsNullOrWhiteSpace(r.Correo)||string.IsNullOrWhiteSpace(r.Password)||string.IsNullOrWhiteSpace(r.ConfirmarPassword))return BadRequest(new ApiResult(false,"Todos los campos son obligatorios."));if(r.Password!=r.ConfirmarPassword)return BadRequest(new ApiResult(false,"Las contraseñas no coinciden."));try{await using var c=new SqlConnection(config.GetConnectionString("DefaultConnection"));await c.OpenAsync();await using var cmd=new SqlCommand("sp_Usuario_Registrar",c){CommandType=CommandType.StoredProcedure};cmd.Parameters.Add("@Nombre",SqlDbType.NVarChar,100).Value=r.Nombre.Trim();cmd.Parameters.Add("@Correo",SqlDbType.NVarChar,150).Value=r.Correo.Trim();cmd.Parameters.Add("@Password",SqlDbType.NVarChar,100).Value=r.Password;var code=Convert.ToInt32(await cmd.ExecuteScalarAsync());return code==1?Ok(new ApiResult(true,"Registro exitoso. Ya puedes iniciar sesión.")):Conflict(new ApiResult(false,"Ese correo ya está registrado."));}catch(Exception ex){return StatusCode(500,new ApiResult(false,"Error de base de datos: "+ex.Message));}}
}
